parameters.text:
=Analyse this meeting and take all necessary actions using your tools.

Meeting: {{ $json.meeting_title }}
Date: {{ $json.meeting_date }}
Organizer: {{ $json.organizer.name }} <{{ $json.organizer.email }}>

Attendees:
{{ $json.attendees.map(a => '- ' + a.name + ' <' + a.email + '>' + (a.is_external ? ' [EXTERNAL — ' + a.company + ']' : ' [Internal]')).join('\n') }}

Full Transcript:
{{ $json.transcript }}

Steps you MUST complete before returning:
1. Call check_blocker_history for each blocker mentioned
2. Call send_action_email once for each unique action item owner
3. Call schedule_followup_meeting if a follow-up was agreed
4. Return ONLY the final JSON object — no intro text

parameters.jsCode:
const input = $input.first().json;
const topic = (input.topic || input.query || '').toLowerCase();

const history = [
  { date: '2026-04-15', topic: 'bosch api documentation', occurrences: 1, impact: 'Firmware integration blocked 2 weeks' },
  { date: '2026-05-01', topic: 'bosch api documentation delay', occurrences: 2, impact: 'Integration testing delayed, sprint missed' },
  { date: '2026-04-08', topic: 'imu sensor calibration drift', occurrences: 1, impact: 'Precision targeting off by 3.1mm' },
  { date: '2026-05-15', topic: 'sensor calibration imu drift', occurrences: 1, impact: 'Precision targeting off by 2.8mm' },
  { date: '2026-05-20', topic: 'power consumption regression', occurrences: 1, impact: 'Build 2.3 exceeded 280W power budget' }
];

const matches = history.filter(h => {
  const words = topic.split(' ');
  return words.some(w => w.length > 3 && h.topic.includes(w));
});

if (matches.length > 0) {
  const total = matches.reduce((s, m) => s + m.occurrences, 0) + 1;
  return JSON.stringify({
    is_recurring: true,
    total_occurrences: total,
    first_seen: matches[matches.length - 1].date,
    last_seen: matches[0].date,
    pattern: 'RECURRING BLOCKER — seen ' + total + ' times in the past 2 months',
    historical_impact: matches.map(m => m.impact).join(' | '),
    recommendation: 'Escalation recommended — assign dedicated owner with hard deadline'
  });
}

return JSON.stringify({
  is_recurring: false,
  total_occurrences: 1,
  pattern: 'First occurrence',
  recommendation: 'Monitor — flag if it appears again next sprint'
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;
const id = 'MTG-' + Math.random().toString(36).substr(2, 6).toUpperCase();
const title = d.title || d.meeting_title || 'Follow-up Meeting';
const date = d.date || d.meeting_date || 'TBD';
const time = d.time || '09:00';
const duration = d.duration_minutes || 60;
const attendees = d.attendees || [];
const agenda = d.agenda || 'Review action items and progress.';

const inviteEmail = {
  subject: 'Meeting Invite: ' + title + ' — ' + date,
  body: 'Hi,\n\nYou are invited to the following follow-up meeting:\n\nTitle: ' + title + '\nDate: ' + date + ' at ' + time + '\nDuration: ' + duration + ' minutes\nAgenda: ' + agenda + '\n\nAttendees:\n' + attendees.join('\n') + '\n\n[DEMO] In production a real Teams calendar invite would be sent via Microsoft Graph API.',
  to: attendees
};

return JSON.stringify({
  success: true,
  meeting_id: id,
  title: title,
  scheduled_for: date + ' at ' + time,
  duration: duration + ' minutes',
  attendees: attendees,
  agenda: agenda,
  teams_join_url: 'https://teams.microsoft.com/l/meetup-join/demo/' + id,
  invite_email: inviteEmail,
  status: 'Meeting details generated: ' + title + ' on ' + date,
  note: '[DEMO] In production: Graph API POST /me/calendar/events — invite email would be sent to all attendees'
});

const raw = $input.first().json;
const d = typeof raw === 'string' ? JSON.parse(raw) : raw;

// Accept any parameter name the LLM might use
const name     = d.recipient_name  || d.owner_name  || d.name  || 'Team Member';
const email    = d.recipient_email || d.owner_email || d.email || 'unknown@neura-robotics.com';
const task     = d.task            || d.action      || d.description || 'Action item';
const deadline = d.deadline        || d.due_date    || d.due   || 'TBD';
const priority = (d.priority || 'medium').toUpperCase();
const meeting  = d.meeting_title   || d.meeting     || 'today\'s meeting';
const followup = d.follow_up_date  || d.followup_date || d.follow_up || 'TBD';
const depends  = d.depends_on || null;

const msgId = 'MSG-' + Math.random().toString(36).substr(2, 8).toUpperCase();

const subject = '[Action Required] ' + task + ' — due ' + deadline;

const body = 'Hi ' + name + ',\n\n' +
  'Following ' + meeting + ', you have been assigned the following action item:\n\n' +
  '📌 Task: ' + task + '\n' +
  '⏰ Deadline: ' + deadline + '\n' +
  '🎯 Priority: ' + priority + '\n' +
  (depends ? '🔗 Depends on: ' + depends + '\n' : '') +
  '\nA follow-up review has been scheduled for ' + followup + ' to track progress.\n\n' +
  'Please confirm receipt and flag any blockers as soon as possible.\n\n' +
  'This email was generated by the NEURA AI Meeting Agent.\n' +
  '[DEMO] In production this would be sent via Microsoft Graph API (POST /me/sendMail)';

return JSON.stringify({
  success: true,
  message_id: msgId,
  to: email,
  recipient: name,
  subject: subject,
  body: body,
  priority: priority,
  deadline: deadline,
  status: 'Email ready for ' + name + ' <' + email + '>',
  note: '[DEMO] Not sent — M365 connection pending'
});

const raw = $input.first().json.output || '';
let parsed;

try {
  let text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  // Strip markdown fences
  text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  // Find outermost JSON object
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    parsed = JSON.parse(text.slice(start, end + 1));
  } else {
    throw new Error('No JSON found in output: ' + text.substring(0, 120));
  }
} catch (e) {
  parsed = {
    meeting_summary: 'Agent returned unstructured output — see raw_output',
    action_items: [],
    external_participants_detected: false,
    blockers: [],
    follow_up_meeting: null,
    risk_flags: ['Parse error: ' + e.message],
    raw_output: String(raw).substring(0, 800)
  };
}

return [{ json: parsed }];

const data = $input.first().json;
const items = data.action_items || [];
const followup = data.follow_up_meeting || null;
const meeting = 'Robot Arm Integration Sync — Sprint Review';
const followupDate = followup ? followup.date + ' at ' + followup.time : 'TBD';

const divider = '─'.repeat(60);

// Action item emails
const actionEmails = items.map((item, i) => {
  return {
    email_number: i + 1,
    type: 'Action Item Email',
    to: item.owner_email,
    recipient: item.owner_name,
    subject: '[Action Required] ' + item.task + ' — due ' + item.deadline,
    body: [
      'Hi ' + item.owner_name + ',',
      '',
      'Following today\'s ' + meeting + ', you have been assigned the following action item:',
      '',
      '📌  Task:      ' + item.task,
      '⏰  Deadline:  ' + item.deadline,
      '🎯  Priority:  ' + item.priority.toUpperCase(),
      item.depends_on ? '🔗  Depends on: ' + item.depends_on : null,
      '',
      'A follow-up review has been scheduled for ' + followupDate + ' to track progress.',
      '',
      'Please confirm receipt and flag any blockers as soon as possible.',
      '',
      '— NEURA AI Meeting Agent',
      '[DEMO — not sent. In production: Microsoft Graph API POST /me/sendMail]'
    ].filter(l => l !== null).join('\n')
  };
});

// Follow-up invite email
const inviteEmail = followup ? {
  email_number: items.length + 1,
  type: 'Follow-up Meeting Invite',
  to: followup.attendees,
  subject: 'Meeting Invite: ' + followup.title + ' — ' + followup.date,
  body: [
    'Hi all,',
    '',
    'A follow-up meeting has been scheduled. Please add it to your calendar.',
    '',
    '📅  Title:     ' + followup.title,
    '🗓   Date:      ' + followup.date + ' at ' + followup.time,
    '⏱   Duration:  ' + followup.duration_minutes + ' minutes',
    '📋  Agenda:    ' + followup.agenda,
    '',
    'Attendees:',
    followup.attendees.map(a => '  • ' + a).join('\n'),
    '',
    '🔗  Teams Link: [Generated by Graph API in production]',
    '',
    '— NEURA AI Meeting Agent',
    '[DEMO — not sent. In production: Microsoft Graph API POST /me/calendar/events]'
  ].join('\n')
} : null;

const all = inviteEmail ? [...actionEmails, inviteEmail] : actionEmails;

return all.map(e => ({ json: e }));
